        std::unique_lock<std::mutex> lock(mutex_);
        not_empty_.wait(lock, [this]() { return !queue_.empty(); });

        T value = std::move(queue_.front());
        queue_.pop();

        not_full_.notify_one();

        if (queue_.empty()) {
            empty_cv_.notify_all();  // Notify waiters
