#include <chrono>
#include <mutex>
#include <stack>
#include <iostream>

// Mutex-based stack
template<typename T>
class MutexStack {
private:
    std::stack<T> stack_;
    std::mutex mutex_;

public:
    void push(const T& value) {
        std::lock_guard<std::mutex> lock(mutex_);
        stack_.push(value);
    }

    std::optional<T> try_pop() {
        std::lock_guard<std::mutex> lock(mutex_);
        if (stack_.empty()) return std::nullopt;

        T val = stack_.top();
        stack_.pop();
        return val;
    }
};

// Benchmark
template<typename Stack>
void benchmark(Stack& stack, const std::string& name) {
    const int OPERATIONS = 1000000;
    const int THREADS = 8;

    auto start = std::chrono::high_resolution_clock::now();

    std::vector<std::thread> threads;
    for (int i = 0; i < THREADS; ++i) {
        threads.emplace_back([&stack, OPERATIONS]() {
            for (int j = 0; j < OPERATIONS / THREADS; ++j) {
                stack.push(j);
                stack.try_pop();
            }
        });
    }

    for (auto& t : threads) {
        t.join();
    }

    auto end = std::chrono::high_resolution_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::milliseconds>(end - start);

    std::cout << name << ": " << duration.count() << " ms\n";
}

int main() {
    {
        LockFreeStack<int> stack;
        benchmark(stack, "Lock-Free Stack");
    }

    {
        MutexStack<int> stack;
        benchmark(stack, "Mutex Stack    ");
    }

    return 0;
}

#include <vector>
#include <thread>
#include <iostream>

struct Task {
    int id;
    int complexity;  // Simulated work
};

void worker(int id, LockFreeStack<Task>& global_stack) {
    int tasks_processed = 0;

    while (true) {
        auto task = global_stack.try_pop();

        if (!task) {
            // No more tasks
            std::cout << "Worker " << id << " finished: "
                      << tasks_processed << " tasks\n";
            return;
        }

        // Simulate work
        std::this_thread::sleep_for(
            std::chrono::microseconds(task->complexity)
        );

        ++tasks_processed;
