subsections.content:
**Strong exception guarantee:**
- If operation fails, vector remains unchanged

**Challenges:**
```cpp
void push_back(const T& value) {
    if (size_ == capacity_) {
        reallocate();  // May throw (allocation)
    }

    new (data_ + size_) T(value);  // May throw (copy constructor)
    ++size_;
}
```

**If copy throws after reallocation:**
- Old buffer already destroyed
- Cannot recover

**Solution:** Use move if `noexcept`, else copy:
```cpp
if constexpr (std::is_nothrow_move_constructible_v<T>) {
    // Move elements (fast, noexcept)
} else {
    // Copy elements (slow, but can rollback)
}
```

---

**Rules:**
- **Reallocation invalidates all iterators** (data_ pointer changes)
- **Insertion/erasure invalidates iterators after modification point**

```cpp
std::vector<int> v = {1, 2, 3};
auto it = v.begin();

v.push_back(4);  // May reallocate
*it;  // ← DANGER: it may be invalidated!
```

**How to check if reallocation occurred:**
```cpp
auto* old_data = v.data();
v.push_back(x);
if (v.data() != old_data) {
    // Reallocation happened
}
```

---



```cpp
#include <memory>
#include <algorithm>
#include <stdexcept>
#include <initializer_list>
#include <type_traits>

template<typename T>
class Vector {
private:
    T* data_;
    size_t size_;
    size_t capacity_;

    // ============================================================
    // HELPER: Reallocate with new capacity
    // ============================================================

    void reallocate(size_t new_capacity) {
        // Allocate new buffer
        T* new_data = static_cast<T*>(
            ::operator new(new_capacity * sizeof(T))
        );

        // Move or copy elements
        if constexpr (std::is_nothrow_move_constructible_v<T>) {
            // Move (noexcept - no rollback needed)
            std::uninitialized_move_n(data_, size_, new_data);
        } else {
            // Copy (may throw - use try-catch for rollback)
            size_t i = 0;
            try {
                for (; i < size_; ++i) {
                    new (new_data + i) T(data_[i]);
                }
            } catch (...) {
                // Rollback: destroy constructed elements
                for (size_t j = 0; j < i; ++j) {
                    new_data[j].~T();
                }
                ::operator delete(new_data);
                throw;  // Re-throw
            }
        }

        // Destroy old elements
        for (size_t i = 0; i < size_; ++i) {
            data_[i].~T();
        }

        // Deallocate old buffer
        ::operator delete(data_);

        // Update pointers
        data_ = new_data;
        capacity_ = new_capacity;
    }

public:
    // ============================================================
    // CONSTRUCTORS
    // ============================================================

    Vector()
        : data_(nullptr), size_(0), capacity_(0) {}

    explicit Vector(size_t count, const T& value = T())
        : data_(nullptr), size_(0), capacity_(0)
    {
        reserve(count);
        for (size_t i = 0; i < count; ++i) {
            push_back(value);
        }
    }

    Vector(std::initializer_list<T> init)
        : data_(nullptr), size_(0), capacity_(0)
    {
        reserve(init.size());
        for (const auto& elem : init) {
            push_back(elem);
        }
    }

    // Copy constructor
    Vector(const Vector& other)
        : data_(nullptr), size_(0), capacity_(0)
    {
        reserve(other.size_);
        for (size_t i = 0; i < other.size_; ++i) {
            push_back(other.data_[i]);
        }
    }

    // Move constructor
    Vector(Vector&& other) noexcept
        : data_(other.data_),
          size_(other.size_),
          capacity_(other.capacity_)
    {
        other.data_ = nullptr;
        other.size_ = 0;
        other.capacity_ = 0;
    }

    // ============================================================
    // DESTRUCTOR
    // ============================================================

    ~Vector() {
        // Destroy all elements
        for (size_t i = 0; i < size_; ++i) {
            data_[i].~T();
        }

        // Deallocate buffer
        ::operator delete(data_);
    }

    // ============================================================
    // ASSIGNMENT OPERATORS
    // ============================================================

    Vector& operator=(const Vector& other) {
        if (this != &other) {
            Vector temp(other);  // Copy
            swap(temp);          // Swap (noexcept)
        }
        return *this;
    }

    Vector& operator=(Vector&& other) noexcept {
        if (this != &other) {
            swap(other);
        }
        return *this;
    }

    // ============================================================
    // CAPACITY
    // ============================================================

    size_t size() const noexcept {
        return size_;
    }

    size_t capacity() const noexcept {
        return capacity_;
    }

    bool empty() const noexcept {
        return size_ == 0;
    }

    void reserve(size_t new_capacity) {
        if (new_capacity <= capacity_) {
            return;  // No-op if already sufficient
        }

        reallocate(new_capacity);
    }

    void shrink_to_fit() {
        if (size_ < capacity_) {
            reallocate(size_);
        }
    }

    // ============================================================
    // ELEMENT ACCESS
    // ============================================================

    T& operator[](size_t index) {
        return data_[index];  // No bounds check (like std::vector)
    }

    const T& operator[](size_t index) const {
        return data_[index];
    }

    T& at(size_t index) {
        if (index >= size_) {
            throw std::out_of_range("Vector::at: index out of range");
        }
        return data_[index];
    }

    const T& at(size_t index) const {
        if (index >= size_) {
            throw std::out_of_range("Vector::at: index out of range");
        }
        return data_[index];
    }

    T& front() {
        return data_[0];
    }

    const T& front() const {
        return data_[0];
    }

    T& back() {
        return data_[size_ - 1];
    }

    const T& back() const {
        return data_[size_ - 1];
    }

    T* data() noexcept {
        return data_;
    }

    const T* data() const noexcept {
        return data_;
    }

    // ============================================================
    // MODIFIERS
    // ============================================================

    void push_back(const T& value) {
        if (size_ == capacity_) {
            size_t new_capacity = (capacity_ == 0) ? 1 : capacity_ * 2;
            reserve(new_capacity);
        }

        new (data_ + size_) T(value);  // Placement new
        ++size_;
    }

    void push_back(T&& value) {
        if (size_ == capacity_) {
            size_t new_capacity = (capacity_ == 0) ? 1 : capacity_ * 2;
            reserve(new_capacity);
        }

        new (data_ + size_) T(std::move(value));
        ++size_;
    }

    template<typename... Args>
    void emplace_back(Args&&... args) {
        if (size_ == capacity_) {
            size_t new_capacity = (capacity_ == 0) ? 1 : capacity_ * 2;
            reserve(new_capacity);
        }

        new (data_ + size_) T(std::forward<Args>(args)...);
        ++size_;
    }

    void pop_back() {
        if (size_ > 0) {
            --size_;
            data_[size_].~T();
        }
    }

    void clear() noexcept {
        for (size_t i = 0; i < size_; ++i) {
            data_[i].~T();
        }
        size_ = 0;
    }

    void resize(size_t new_size, const T& value = T()) {
        if (new_size < size_) {
            // Shrink: destroy excess elements
            for (size_t i = new_size; i < size_; ++i) {
                data_[i].~T();
            }
            size_ = new_size;
        } else if (new_size > size_) {
            // Grow: construct new elements
            reserve(new_size);
            for (size_t i = size_; i < new_size; ++i) {
                new (data_ + i) T(value);
            }
            size_ = new_size;
        }
    }

    void swap(Vector& other) noexcept {
        std::swap(data_, other.data_);
        std::swap(size_, other.size_);
        std::swap(capacity_, other.capacity_);
    }

    // ============================================================
    // ITERATORS (simplified)
    // ============================================================

    using iterator = T*;
    using const_iterator = const T*;

    iterator begin() noexcept {
        return data_;
    }

    const_iterator begin() const noexcept {
        return data_;
    }

    iterator end() noexcept {
        return data_ + size_;
    }

    const_iterator end() const noexcept {
        return data_ + size_;
    }
};
```

