#include <memory>
#include <algorithm>
#include <stdexcept>
#include <initializer_list>
#include <type_traits>

template<typename T>
class Vector {
private:
    T* data_;
    size_t size_;
    size_t capacity_;

    // ============================================================
    // HELPER: Reallocate with new capacity
    // ============================================================

    void reallocate(size_t new_capacity) {
        // Allocate new buffer
        T* new_data = static_cast<T*>(
            ::operator new(new_capacity * sizeof(T))
        );

        // Move or copy elements
        if constexpr (std::is_nothrow_move_constructible_v<T>) {
            // Move (noexcept - no rollback needed)
            std::uninitialized_move_n(data_, size_, new_data);
        } else {
            // Copy (may throw - use try-catch for rollback)
            size_t i = 0;
            try {
                for (; i < size_; ++i) {
                    new (new_data + i) T(data_[i]);
                }
            } catch (...) {
                // Rollback: destroy constructed elements
                for (size_t j = 0; j < i; ++j) {
                    new_data[j].~T();
                }
                ::operator delete(new_data);
                throw;  // Re-throw
            }
        }

        // Destroy old elements
        for (size_t i = 0; i < size_; ++i) {
            data_[i].~T();
        }

        // Deallocate old buffer
        ::operator delete(data_);

        // Update pointers
        data_ = new_data;
        capacity_ = new_capacity;
    }

public:
    // ============================================================
    // CONSTRUCTORS
    // ============================================================

    Vector()
        : data_(nullptr), size_(0), capacity_(0) {}

    explicit Vector(size_t count, const T& value = T())
        : data_(nullptr), size_(0), capacity_(0)
    {
        reserve(count);
        for (size_t i = 0; i < count; ++i) {
            push_back(value);
        }
    }

    Vector(std::initializer_list<T> init)
        : data_(nullptr), size_(0), capacity_(0)
    {
        reserve(init.size());
        for (const auto& elem : init) {
            push_back(elem);
        }
    }

    // Copy constructor
    Vector(const Vector& other)
        : data_(nullptr), size_(0), capacity_(0)
    {
        reserve(other.size_);
        for (size_t i = 0; i < other.size_; ++i) {
            push_back(other.data_[i]);
        }
    }

    // Move constructor
    Vector(Vector&& other) noexcept
        : data_(other.data_),
          size_(other.size_),
          capacity_(other.capacity_)
    {
        other.data_ = nullptr;
        other.size_ = 0;
        other.capacity_ = 0;
    }

    // ============================================================
    // DESTRUCTOR
    // ============================================================

    ~Vector() {
        // Destroy all elements
        for (size_t i = 0; i < size_; ++i) {
            data_[i].~T();
        }

        // Deallocate buffer
        ::operator delete(data_);
    }

    // ============================================================
    // ASSIGNMENT OPERATORS
    // ============================================================

    Vector& operator=(const Vector& other) {
        if (this != &other) {
            Vector temp(other);  // Copy
            swap(temp);          // Swap (noexcept)
        }
        return *this;
    }

    Vector& operator=(Vector&& other) noexcept {
        if (this != &other) {
            swap(other);
        }
        return *this;
    }

    // ============================================================
    // CAPACITY
    // ============================================================

    size_t size() const noexcept {
        return size_;
    }

    size_t capacity() const noexcept {
        return capacity_;
    }

    bool empty() const noexcept {
        return size_ == 0;
    }

    void reserve(size_t new_capacity) {
        if (new_capacity <= capacity_) {
            return;  // No-op if already sufficient
        }

        reallocate(new_capacity);
    }

    void shrink_to_fit() {
        if (size_ < capacity_) {
            reallocate(size_);
        }
    }

    // ============================================================
    // ELEMENT ACCESS
    // ============================================================

    T& operator[](size_t index) {
        return data_[index];  // No bounds check (like std::vector)
    }

    const T& operator[](size_t index) const {
        return data_[index];
    }

    T& at(size_t index) {
        if (index >= size_) {
            throw std::out_of_range("Vector::at: index out of range");
        }
        return data_[index];
    }

    const T& at(size_t index) const {
        if (index >= size_) {
            throw std::out_of_range("Vector::at: index out of range");
        }
        return data_[index];
    }

    T& front() {
        return data_[0];
    }

    const T& front() const {
        return data_[0];
    }

    T& back() {
        return data_[size_ - 1];
    }

    const T& back() const {
        return data_[size_ - 1];
    }

    T* data() noexcept {
        return data_;
    }

    const T* data() const noexcept {
        return data_;
    }

    // ============================================================
    // MODIFIERS
    // ============================================================

    void push_back(const T& value) {
        if (size_ == capacity_) {
            size_t new_capacity = (capacity_ == 0) ? 1 : capacity_ * 2;
            reserve(new_capacity);
        }

        new (data_ + size_) T(value);  // Placement new
        ++size_;
    }

    void push_back(T&& value) {
        if (size_ == capacity_) {
            size_t new_capacity = (capacity_ == 0) ? 1 : capacity_ * 2;
            reserve(new_capacity);
        }

        new (data_ + size_) T(std::move(value));
        ++size_;
    }

    template<typename... Args>
    void emplace_back(Args&&... args) {
        if (size_ == capacity_) {
            size_t new_capacity = (capacity_ == 0) ? 1 : capacity_ * 2;
            reserve(new_capacity);
        }

        new (data_ + size_) T(std::forward<Args>(args)...);
