        // pos invalidated! Recalculate:
        pos = begin() + index;
    }

    // Shift elements right
    for (size_t i = size_; i > index; --i) {
        new (data_ + i) T(std::move(data_[i - 1]));
        data_[i - 1].~T();
    }

    // Insert new element
    new (data_ + index) T(value);
    ++size_;

    return begin() + index;
}

