        size_t new_capacity = (capacity_ == 0) ? 1 :
            (capacity_ * GrowthNumerator) / GrowthDenominator;

        reserve(new_capacity);
    }

public:
    void push_back(const T& value) {
        if (size_ == capacity_) {
            grow();
        }
        // ...
    }
};

