    std::unordered_map<Key, typename std::list<Node>::iterator> map_;

public:
    explicit LRUCache(size_t capacity) : capacity_(capacity) {}

    std::optional<Value> get(const Key& key) {
        auto it = map_.find(key);

        if (it == map_.end()) {
