subsections.content:
```
Thread 1 ──┐
Thread 2 ──┼──> [Queue] ──> [Logger Thread] ──> File
Thread 3 ──┘
```

**Producer threads:** Push log messages to queue
**Consumer thread:** Pops messages, writes to file

---



```cpp
#include <queue>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <fstream>
#include <sstream>
#include <chrono>
#include <iomanip>

enum class LogLevel {
    DEBUG, INFO, WARN, ERROR
};

class Logger {
private:
    struct LogMessage {
        LogLevel level;
        std::string message;
        std::chrono::system_clock::time_point timestamp;
    };

    std::queue<LogMessage> queue_;
    std::mutex mutex_;
    std::condition_variable cv_;
    std::thread worker_;
    bool stop_{false};

    std::ofstream file_;
    LogLevel min_level_{LogLevel::DEBUG};

    void worker_loop() {
        while (true) {
            LogMessage msg;

            {
                std::unique_lock<std::mutex> lock(mutex_);
                cv_.wait(lock, [this]() {
                    return !queue_.empty() || stop_;
                });

                if (stop_ && queue_.empty()) {
                    return;
                }

                msg = std::move(queue_.front());
                queue_.pop();
            }

            write_to_file(msg);
        }
    }

    void write_to_file(const LogMessage& msg) {
        if (msg.level < min_level_) {
            return;
        }

        auto time_t = std::chrono::system_clock::to_time_t(msg.timestamp);
        auto tm = *std::localtime(&time_t);

        file_ << std::put_time(&tm, "%Y-%m-%d %H:%M:%S") << " ";
        file_ << "[" << level_to_string(msg.level) << "] ";
        file_ << msg.message << '\n';
        file_.flush();
    }

    static const char* level_to_string(LogLevel level) {
        switch (level) {
            case LogLevel::DEBUG: return "DEBUG";
            case LogLevel::INFO:  return "INFO";
            case LogLevel::WARN:  return "WARN";
            case LogLevel::ERROR: return "ERROR";
            default: return "UNKNOWN";
        }
    }

public:
    explicit Logger(const std::string& filename, LogLevel min_level = LogLevel::DEBUG)
        : file_(filename, std::ios::app), min_level_(min_level)
    {
        worker_ = std::thread(&Logger::worker_loop, this);
    }

    ~Logger() {
        {
            std::lock_guard<std::mutex> lock(mutex_);
            stop_ = true;
        }
        cv_.notify_one();
        worker_.join();
    }

    void log(LogLevel level, const std::string& message) {
        {
            std::lock_guard<std::mutex> lock(mutex_);
            queue_.push({level, message, std::chrono::system_clock::now()});
        }
        cv_.notify_one();
    }

    void debug(const std::string& msg) { log(LogLevel::DEBUG, msg); }
    void info(const std::string& msg)  { log(LogLevel::INFO, msg); }
    void warn(const std::string& msg)  { log(LogLevel::WARN, msg); }
    void error(const std::string& msg) { log(LogLevel::ERROR, msg); }
};
```

---

